channels = get_channels()
all_messages = []
for c in channels:
    msgs = read_channel_messages(c)
    all_messages = [*all_messages, *msgs]

counts = {}
for m in all_messages:
    counts = {**counts, m.sender: counts.get(m.sender, 0) + 1}

top_user = max(counts.items(), key=lambda x: x[1])[0]
print("Top user:", top_user)
send_direct_message(top_user, "Congrats on being the most active user!")
